// Query helpers
export const getPresentationsByType = (type: PresentationType): Presentation[] =>
  presentations.filter(p => p.type === type)

export const getFirstAuthorPresentations = (): Presentation[] =>
  presentations.filter(p => p.isFirstAuthor)

export const getPresentationsByYear = (year: number): Presentation[] =>
  presentations.filter(p => p.year === year)

export const getPresentationsByVenue = (venue: string): Presentation[] =>
  presentations.filter(p => p.venue.toLowerCase().includes(venue.toLowerCase()))
